package com.parkflow.mall.gateway;
import com.parkflow.mall.gateway.controller.MerchantGatewayController; import com.parkflow.mall.gateway.merchant.MerchantServiceProxy; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.*; import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest; import org.springframework.boot.test.mock.mockito.MockBean; import org.springframework.http.*; import org.springframework.test.web.servlet.MockMvc; import static org.mockito.ArgumentMatchers.*; import static org.mockito.Mockito.*; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@WebMvcTest(MerchantGatewayController.class) class MerchantGatewayControllerTests { @Autowired MockMvc mvc; @MockBean MerchantServiceProxy proxy; @Test void merchantRoutesExistAndForwardAuthorization() throws Exception { when(proxy.validate(anyString(),anyString())).thenReturn(ResponseEntity.ok().contentType(MediaType.APPLICATION_JSON).body("{\"status\":\"ACCEPTED\"}")); when(proxy.history(anyString(),anyString())).thenReturn(ResponseEntity.ok().contentType(MediaType.APPLICATION_JSON).body("{\"validations\":[]}")); mvc.perform(post("/api/merchant/validations").header("Authorization","Bearer merchant-token").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk()); verify(proxy).validate("Bearer merchant-token","{}"); mvc.perform(get("/api/merchant/validations").param("sessionId","session-1").header("Authorization","Bearer merchant-token")).andExpect(status().isOk()); verify(proxy).history("Bearer merchant-token","session-1"); mvc.perform(post("/internal/parking/sessions/session-1/discount").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isNotFound()); } }
